# 复用上游已计算结果，组装三类站点最终对比并设置必需输出变量

def _required_float_from_dict(source_dict, key, label):
    if key not in source_dict or source_dict[key] is None:
        raise ValueError(f"{label} 缺失，无法设置必需输出变量。")
    return float(source_dict[key])

max_pm25_s87 = _required_float_from_dict(
    stats_fireworks_peak_pm25_by_station, station_id_s87, "文 明里站点 PM2.5 峰值"
)
max_pm25_s284 = _required_float_from_dict(
    stats_fireworks_peak_pm25_by_station, station_id_s284, "平泉林业和草原局站点 PM2.5 峰值"
)
max_pm25_s1 = _required_float_from_dict(
    stats_fireworks_peak_pm25_by_station, station_id_s1, "西南高教站点 PM2.5 峰值"
)

mean_aqi_s87 = _required_float_from_dict(
    stats_fireworks_mean_aqi_by_station, station_id_s87, "文 明里站点平均 AQI"
)
mean_aqi_s284 = _required_float_from_dict(
    stats_fireworks_mean_aqi_by_station, station_id_s284, "平泉林业和草原局站点平均 AQI"
)
mean_aqi_s1 = _required_float_from_dict(
    stats_fireworks_mean_aqi_by_station, station_id_s1, "西南高教站点平均 AQI"
)

if stats_fireworks_strongest_impact_station_id_candidate is None:
    raise ValueError("最强影响站点候选值缺失，无法设置 strongest_impact_station_id。")
strongest_impact_station_id = int(stats_fireworks_strongest_impact_station_id_candidate)

print("max_pm25_s87 =", max_pm25_s87)
print("max_pm25_s284 =", max_pm25_s284)
print("max_pm25_s1 =", max_pm25_s1)
print("mean_aqi_s87 =", mean_aqi_s87)
print("mean_aqi_s284 =", mean_aqi_s284)
print("mean_aqi_s1 =", mean_aqi_s1)
print("strongest_impact_station_id =", strongest_impact_station_id)
